    int maxFreq(string s, int maxLetters, int minSize, int maxSize) {
        int n = s.size();
        int maxOccur = 0;
        unordered_map<string, int> freq;

        for (int len = minSize; len <= min(maxSize, n); ++len) {
            vector<int> cnt(26, 0);
            int unique = 0;
            for (int i = 0; i < n; ++i) {
                if (i >= len) {
                    int left = s[i - len] - 'a';
                    if (--cnt[left] == 0) --unique;
                }
                int right = s[i] - 'a';
                if (cnt[right]++ == 0) ++unique;

                if (i >= len - 1 && unique <= maxLetters) {
                    string sub = s.substr(i - len + 1, len);
                    maxOccur = max(maxOccur, ++freq[sub]);
                }
            }
            if (maxOccur > 0) break;
        }
        return maxOccur;
    }
};
